component.data-model:
struct Engine { buffers: HashMap<PathBuf, Buffer>, symbol_index: SymbolIndex, watcher: FileWatcher, parsers: ParserPool, }
struct Buffer { path: PathBuf, rope: Rope, // ropey::Rope — the file content tree: Option<Tree>, // tree-sitter parse tree language: Option<Language>, // detected language encoding: Encoding, // UTF-8, Latin-1, etc. line_ending: LineEnding, // LF, CRLF, Mixed content_hash: u64, // xxhash of current content disk_hash: u64, // xxhash of on-disk content (for stale detection) undo_stack: Vec<UndoEntry>, redo_stack: Vec<UndoEntry>, dirty: bool, // buffer differs from disk last_modified: SystemTime, // on-disk mtime at last read }
struct UndoEntry { rope_snapshot: Rope, // cheap clone (COW) tree_snapshot: Option<Tree>, description: String, // "edit lines 45-52", "insert at line 10" timestamp: Instant, }
enum LineEnding { LF, CRLF, Mixed } enum Encoding { Utf8, Latin1 }

struct SymbolIndex {
    definitions: HashMap<String, Vec<SymbolDef>>,
    // name → list of definitions (same name can exist in multiple files)
}

struct SymbolDef {
    name: String,
    kind: SymbolKind,   // Function, Class, Method, Struct, Enum, etc.
    path: PathBuf,
    start_line: usize,
    end_line: usize,
    signature: String,  // first line of the definition (for preview)
}

enum SymbolKind {
    Function, Class, Method, Struct, Enum, Trait, Interface,
    Import, Variable, Constant, Module
}

output.field:
Structural outline if language is supported. Array of:
{ name: string, kind: string, start_line: int, end_line: int, children: array }
Null if language has no grammar.

input.field:
Array of edit operations, each:
{
  start_line: integer,  // first line to replace (1-indexed)
  end_line: integer,    // last line to replace (inclusive)
  content: string       // replacement content. Empty string = delete lines.
                        // Content is split on newlines. Final newline is auto-added
                        // if the original range ended with one.
}

output.field:
Array of:
{
  path: string,
  matches: [{ line: int, text: string, column_start: int, column_end: int }]
}
